using UnityEngine;
public class Script {
  public static object Main() {
    var sb = new System.Text.StringBuilder();
    var panelGO = GameObject.Find("control pannel setup");
    var ctrlT   = panelGO?.transform.Find("ctrl");

    // Check all buttons that have CNC3DButton
    var buttons = GameObject.FindObjectsByType<CNC3DButton>(FindObjectsSortMode.None);
    sb.AppendLine("CNC3DButton instances: " + buttons.Length);
    foreach (var btn in buttons) {
      var col = btn.GetComponent<Collider>();
      sb.AppendLine("\nButton: '" + btn.gameObject.name + "'");
      sb.AppendLine("  World pos  : " + btn.transform.position);
      sb.AppendLine("  Local pos  : " + btn.transform.localPosition);
      sb.AppendLine("  World scale: " + btn.transform.lossyScale);
      if (col != null) {
        sb.AppendLine("  Collider   : " + col.GetType().Name + " enabled=" + col.enabled);
        sb.AppendLine("  Bounds ctr : " + col.bounds.center);
        sb.AppendLine("  Bounds size: " + col.bounds.size);
        var box = col as BoxCollider;
        if (box != null) {
          sb.AppendLine("  Box center : " + box.center);
          sb.AppendLine("  Box size   : " + box.size);
        }
      } else sb.AppendLine("  Collider   : NONE");
      sb.AppendLine("  Parent     : " + (btn.transform.parent?.name ?? "root"));
    }
    return sb.ToString();
  }
}
